VALUES
  ('elementary-e0adf6cd-moex-00179', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '依照我國憲法本文、增修條文與教育基本法的規定，下列對於馬祖（連江縣）教育事務規範之敘述，何者 錯誤？', '["國家應注重馬祖與其他地區間教育事務是否均衡發展", "國家應優先補助馬祖的教育事項", "國家應保障扶助馬祖教育文化的發展，並制定法律作為依據", "馬祖的教育文化經費應全部由國庫支應"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "a661637898b8", "answer_pdf_sha1": "78bf427c56e6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00180', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '我國憲法、教育基本法及國民教育法對私立學校有關的規範，下列各敘述何者正確？', '["此三部法規，僅有憲法與教育基本法明文保障私人興學自由", "政府如將公立國中小學委託私人辦理，應適用教育基本法處理相關事項", "私立學校進用教師或職員，均由校長聘任或遴用，並須報主管機關備查", "私立學校的財務運用應自負盈虧，政府原則上不應給予補助，並應依法監督"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "a661637898b8", "answer_pdf_sha1": "78bf427c56e6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00181', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '下列何者並非教育基本法所揭示的教育目的？', '["培養民主法治的基本觀念", "促進經濟與社會的公平發展", "提升對多元文化的瞭解與關懷", "增進人民鄉土關懷及保護生態環境"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "a661637898b8", "answer_pdf_sha1": "78bf427c56e6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00182', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '下列各項教育領域的行政命令，何者法律性質與其他三者不同？', '["國民體育法施行細則", "本國語文教育推動會設置要點", "國民教育階段家長參與學校教育事務辦法", "國民小學與國民中學班級編制及教職員員額編制準則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "a661637898b8", "answer_pdf_sha1": "78bf427c56e6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00183', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '下列各類教育人員的權利義務事項，何者不是適用或準用教師法規定辦理？', '["軍事院校中依教育人員任用條例聘任之教師的停聘事項", "公立幼兒園教師的解聘資遣事項", "各級學校校長的申訴事項", "公立學校代理教師的終止聘約或停止聘約執行之事項"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "a661637898b8", "answer_pdf_sha1": "78bf427c56e6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00184', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '大學法對直轄市設立的市立大學（下稱該校）訂有相關規範，下列何者不符合該法規定？', '["該校如須變更或停辦，由所屬直轄市依序報經教育部核定或調整", "該校擬與他校合併時，應經校務會議同意與所屬直轄市政府同意後，報教育部核定後才能執行", "該校大學校長遴選委員會的組織、運作及其他應遵行事項，與其他國立大學相同，均由教育部定之", "該校校長如於所屬直轄市政府辦理評鑑時，表達無續任意願，其即不得參加原學校新任校長遴選"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "a661637898b8", "answer_pdf_sha1": "78bf427c56e6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00185', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '下列何者不屬於專任教師依教師法或國民教育法應負的義務？', '["實施學生家庭訪問", "依法令參與學校行政工作", "參與教學有關之研究、進修", "參與校務會議"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "a661637898b8", "answer_pdf_sha1": "78bf427c56e6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00186', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '學校為身心障礙學生訂定個別化教育計畫時，下列何者不符合特殊教育法之規定？', '["學生及其法定代理人或實際照顧者都應該參與訂定程序", "學生經評估有需求時，學校應邀請相關專業人員參與討論", "所有身心障礙學生的個別化教育計畫均應於開學後1個月內訂定完畢，且每學期檢討之", "學校訂定個別化教育計畫時應參考中央主管機關訂定之指引"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "a661637898b8", "answer_pdf_sha1": "78bf427c56e6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00187', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '有關家庭教育的實施方式，下列各項敘述何者錯誤？', '["僅有高中以下學校須在正式課程之外實施家庭教育課程", "各級主管機關均應組成家庭教育諮詢委員會，並以首長為主任委員", "主管機關應鼓勵各師資培育大專院校將家庭教育課程設為必修或通識課程", "各級學校所在地主管機關應視需要研訂優先接受家庭教育服務之對象及措施"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "a661637898b8", "answer_pdf_sha1": "78bf427c56e6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL),
  ('elementary-e0adf6cd-moex-00188', 'elementary-e0adf6cd', 'elementary-e0adf6cd-moex-114-e740d83c', 'sub-elementary-e0adf6cd-04', NULL, 'single_choice', '下列有關教師申訴評議委員會（簡稱申評會）組織規範之說明，何者正確？', '["各主管教育機關申評會委員中未兼行政職務之教師人數不得少於委員總數二分之一", "申評會主席由委員互選產生，其任期與委員任期相同，均為2年", "大專院校的申評會組織與運作辦法，由申評會自行訂定或修正，以維護其獨立性", "大專院校如無教師會，申評會中教師組織代表由教育階段相當之他校教師會或直轄市、縣（市）教師會 推薦"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:29:37+00:00", "source_pdf_sha1": "a661637898b8", "answer_pdf_sha1": "78bf427c56e6", "source_family": "moex-gov-tw", "moex": {"exam_code": "114010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "教育法規大意", "year": "114", "exam_name": "114年公務人員初等考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "教育行政"}'::jsonb, NULL)
